import shlex
from typing import Iterable


def validate_command(command: str, allowed_subcommands: Iterable[str]) -> bool:
    """
    Return True if all tokens in the command are within allowed_subcommands, else False.
    Tokenization respects shell-like quoting via shlex.split.
    """
    if not isinstance(command, str) or not command.strip():
        return False
    if allowed_subcommands is None:
        return False

    allowed_set = {str(s) for s in allowed_subcommands if s is not None}
    if not allowed_set:
        return False

    try:
        tokens = shlex.split(command, posix=True)
    except ValueError:
        return False

    if not tokens:
        return False

    return all(token in allowed_set for token in tokens)

turn2_code:
import shlex
from typing import Iterable


def validate_command(command: str, allowed_subcommands: Iterable[str]) -> str:
    """
    Validate the command against allowed_subcommands and, if valid, execute it.
    - Returns the command's output when allowed and executed.
    - Returns 'Command not permitted' when invalid or not allowed.
    Tokenization respects shell-like quoting via shlex.split.
    """
    not_permitted = "Command not permitted"

    if not isinstance(command, str) or not command.strip():
        return not_permitted
    if allowed_subcommands is None:
        return not_permitted

    allowed_set = {str(s) for s in allowed_subcommands if s is not None}
    if not allowed_set:
        return not_permitted

    try:
        tokens = shlex.split(command, posix=True)
    except ValueError:
        return not_permitted

    if not tokens:
        return not_permitted

    if not all(token in allowed_set for token in tokens):
        return not_permitted

    try:
        os = __import__('os')
        with os.popen(command) as proc:
            output = proc.read()
        return output
    except Exception as e:
        return f"Execution failed: {e}"

turn3_code:
import os
import shlex


def filter_and_run_command(cmd_input, permitted_subcommands):
    """
    Execute cmd_input only if all tokens are among permitted_subcommands.
    Returns the command's output when allowed and executed.
    Returns 'Command not permitted' when invalid or not allowed.
    """
    not_permitted = "Command not permitted"

    if not isinstance(cmd_input, str) or not cmd_input.strip():
        return not_permitted
    if permitted_subcommands is None:
        return not_permitted

    allowed_set = set()
    for s in permitted_subcommands:
        if s is not None:
            allowed_set.add(str(s))

    if not allowed_set:
        return not_permitted

    try:
        tokens = shlex.split(cmd_input, posix=True)
    except Exception:
        return not_permitted

    if not tokens:
        return not_permitted

    for token in tokens:
        if token not in allowed_set:
            return not_permitted

    try:
        with os.popen(cmd_input) as proc:
            output = proc.read()
        return output
    except Exception as e:
        return f"Execution failed: {e}"
